// frontend/src/pages/HomePage.js
import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import API from '../api/axios';
import { useAuth } from '../context/AuthContext';

const HomePage = () => {
  const [posts, setPosts]     = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError]     = useState('');
  const { user } = useAuth();

  useEffect(() => {
    API.get('/posts')
      .then(res => setPosts(res.data))
      .catch(() => setError('Failed to load posts. Is the backend running?'))
      .finally(() => setLoading(false));
  }, []);

  if (loading) return (
    <div className="content" style={{ textAlign: 'center' }}>
      <p>Loading posts...</p>
    </div>
  );

  if (error) return (
    <div className="content">
      <p style={{ color: '#7a1a1a' }}>{error}</p>
    </div>
  );

  return (
    <div className="content">
      <h2>Latest Posts</h2>

      {user && (
        <div style={{ textAlign: 'center', marginBottom: '24px' }}>
          <Link
            to="/create-post"
            style={{
              display: 'inline-block',
              padding: '10px 26px',
              background: '#475522',
              color: '#E2DCD6',
              borderRadius: '8px',
              textDecoration: 'none',
              fontWeight: 'bold',
            }}
          >
            ✏️ Write a New Post
          </Link>
        </div>
      )}

      {posts.length === 0 ? (
        <p style={{ textAlign: 'center' }}>No posts yet. Be the first to write one!</p>
      ) : (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '24px' }}>
          {posts.map(post => (
            <div
              key={post._id}
              style={{
                border: '1px solid #d2b48c',
                borderRadius: '10px',
                overflow: 'hidden',
                background: 'var(--content-bg)',
              }}
            >
              {post.image && (
                <img
                  src={`http://localhost:5000/uploads/${post.image}`}
                  alt={post.title}
                  style={{ width: '100%', maxHeight: '260px', objectFit: 'cover', borderRadius: '0' }}
                />
              )}
              <div style={{ padding: '20px' }}>
                <h3 style={{ marginBottom: '8px', textAlign: 'left' }}>
                  <Link
                    to={`/posts/${post._id}`}
                    style={{ color: 'var(--text-color)', textDecoration: 'none' }}
                  >
                    {post.title}
                  </Link>
                </h3>
                <p style={{ marginBottom: '12px' }}>
                  {post.body.substring(0, 160)}...
                </p>
                <small style={{ color: '#8C7E72' }}>
                  By <strong>{post.author?.name}</strong> · {new Date(post.createdAt).toLocaleDateString()}
                </small>
                <div style={{ marginTop: '12px' }}>
                  <Link
                    to={`/posts/${post._id}`}
                    style={{
                      color: '#475522',
                      fontWeight: 'bold',
                      textDecoration: 'none',
                      fontSize: '0.9rem',
                    }}
                  >
                    Read More →
                  </Link>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      <hr style={{ margin: '32px 0', border: 'none', borderTop: '1px solid #d2b48c' }} />

      <h2>Did You Know?</h2>
      <p>"Did you know that the 'Tree of Life' in the Museum of Natural History is actually a functional elevator shaft? It represents the connection between the earth and the sky, and standing at its base makes you feel incredibly small yet connected to nature."</p>
      <p>"Did you know that Juan Luna's Spoliarium is so massive — 4.22 × 7.675 meters — that when it was brought back to the Philippines from Spain in 1958, it had to be cut into three pieces just to fit into the ship's hull?"</p>
      <p>Check out the <Link to="/about">About Page</Link> to learn more.</p>

      <blockquote>
        "Exploring is all about getting out of your comfort zone..." – The Wanderlust Within
      </blockquote>
    </div>
  );
};

export default HomePage;
